import subprocess
import sys

def run_with_timeout(code: str, timeout: int = 10) -> dict:
    try:
        proc = subprocess.run(
            [sys.executable, "-c", code],
            capture_output=True,
            text=True,
            timeout=timeout,   # sends SIGKILL after N seconds wall-clock
        )
        return {"stdout": proc.stdout[:8192], "error": None}
    except subprocess.TimeoutExpired:
        return {"stdout": "", "error": f"Timed out after {timeout}s"}

import resource
import os

def set_cpu_limit(cpu_seconds: int = 8):
    """
    RLIMIT_CPU counts CPU time used, not wall-clock time.
    A process sleeping for 10s uses 0 CPU seconds and is not killed.
    Combine with subprocess timeout= for complete coverage.
    """
    # Soft limit triggers SIGXCPU; hard limit triggers SIGKILL
    resource.setrlimit(resource.RLIMIT_CPU, (cpu_seconds, cpu_seconds + 2))

def run_with_cpu_limit(code: str, timeout: int = 10) -> dict:
    try:
        proc = subprocess.run(
            [sys.executable, "-c", code],
            capture_output=True,
            text=True,
            timeout=timeout,
            preexec_fn=lambda: set_cpu_limit(timeout - 1),
        )
        return {"stdout": proc.stdout[:8192], "error": None}
    except subprocess.TimeoutExpired:
        return {"stdout": "", "error": f"Timed out after {timeout}s"}

import resource

def set_memory_limit(mb: int = 256):
    """
    RLIMIT_AS limits the total virtual address space, not just RSS.
    Python's mmap usage (numpy arrays, etc.) counts against this limit.
    Set it conservatively — numpy may need more virtual space than physical.
    """
    limit_bytes = mb * 1024 * 1024
    resource.setrlimit(resource.RLIMIT_AS, (limit_bytes, limit_bytes))

# Combine with Docker --memory for belt-and-suspenders
def run_with_memory_limit(code: str, memory_mb: int = 256) -> dict:
    try:
        proc = subprocess.run(
            [sys.executable, "-c", code],
            capture_output=True, text=True, timeout=15,
            preexec_fn=lambda: set_memory_limit(memory_mb),
        )
        return {"stdout": proc.stdout[:8192],
                "error": None if proc.returncode == 0 else proc.stderr[:1024]}
    except subprocess.TimeoutExpired:
        return {"stdout": "", "error": "Timed out"}

import resource

def set_file_limits(
    max_file_size_mb: int = 32,
    max_open_files: int = 64,
):
    """
    RLIMIT_FSIZE: max size of any single file the process writes.
    RLIMIT_NOFILE: max number of simultaneously open file descriptors.
    """
    # File size limit
    size_bytes = max_file_size_mb * 1024 * 1024
    resource.setrlimit(resource.RLIMIT_FSIZE, (size_bytes, size_bytes))

    # Open file descriptors (default often 1024; lower it)
    resource.setrlimit(resource.RLIMIT_NOFILE, (max_open_files, max_open_files))

def run_with_file_limits(code: str) -> dict:
    def preexec():
        set_memory_limit(256)
        set_cpu_limit(10)
        set_process_limit(32)
        set_file_limits(32, 64)

    try:
        proc = subprocess.run(
            [sys.executable, "-c", code],
            capture_output=True, text=True, timeout=12,
            preexec_fn=preexec,
        )
        return {"stdout": proc.stdout[:8192],
                "error": None if proc.returncode == 0 else proc.stderr[:1024]}
    except subprocess.TimeoutExpired:
        return {"stdout": "", "error": "Timed out"}

import subprocess
import resource
import sys
import os

def make_preexec(memory_mb=256, cpu_seconds=10, max_procs=32, max_file_mb=32):
    def preexec():
        if os.name == "nt":
            return  # setrlimit not available on Windows
        mb = 1024 * 1024
        resource.setrlimit(resource.RLIMIT_AS, (memory_mb * mb, memory_mb * mb))
        resource.setrlimit(resource.RLIMIT_CPU, (cpu_seconds, cpu_seconds + 2))
        resource.setrlimit(resource.RLIMIT_NPROC, (max_procs, max_procs))
        resource.setrlimit(resource.RLIMIT_FSIZE, (max_file_mb * mb, max_file_mb * mb))
        resource.setrlimit(resource.RLIMIT_NOFILE, (64, 64))
    return preexec

def safe_execute(
    code: str,
    timeout: int = 12,
    memory_mb: int = 256,
) -> dict:
    """Execute code with comprehensive resource limits."""
    try:
        proc = subprocess.run(
            [sys.executable, "-c", code],
            capture_output=True,
            text=True,
            timeout=timeout,
            preexec_fn=make_preexec(
                memory_mb=memory_mb,
                cpu_seconds=timeout - 2,
            ),
            env={"PATH": "/usr/local/bin:/usr/bin:/bin", "HOME": "/tmp"},
            cwd="/tmp",
        )
        return {
            "stdout": proc.stdout[:8192],
            "stderr": proc.stderr[:2048],
            "returncode": proc.returncode,
            "error": None if proc.returncode == 0 else proc.stderr[:1024],
        }
    except subprocess.TimeoutExpired:
        return {"stdout": "", "stderr": "", "returncode": -1,
                "error": f"Killed: exceeded {timeout}s wall-clock timeout"}
    except MemoryError:
        return {"stdout": "", "stderr": "", "returncode": -1,
                "error": "Killed: memory limit exceeded"}
